import{_ as e,o as a,c as l,ah as r}from"./chunks/framework.C80vgv3d.js";const f=JSON.parse('{"title":"🚀 概览介绍：向上攀爬的脚印","description":"","frontmatter":{},"headers":[],"relativePath":"java/index.md","filePath":"java/index.md"}'),n={name:"java/index.md"};function i(s,t,o,d,g,h){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="🚀-概览介绍-向上攀爬的脚印" tabindex="-1">🚀 概览介绍：向上攀爬的脚印 <a class="header-anchor" href="#🚀-概览介绍-向上攀爬的脚印" aria-label="Permalink to “🚀 概览介绍：向上攀爬的脚印”">​</a></h1><blockquote><p><strong>好记性不如烂笔头。</strong></p></blockquote><h2 id="🏗️-核心实战方向" tabindex="-1">🏗️ 核心实战方向 <a class="header-anchor" href="#🏗️-核心实战方向" aria-label="Permalink to “🏗️ 核心实战方向”">​</a></h2><p>这里不聊乏味的定义，只记录“怎么做”和“为什么这么做”：</p><h3 id="_1-微服务生态整合-spring-cloud" tabindex="-1">1. 微服务生态整合 (Spring Cloud) <a class="header-anchor" href="#_1-微服务生态整合-spring-cloud" aria-label="Permalink to “1. 微服务生态整合 (Spring Cloud)”">​</a></h3><ul><li><strong>服务治理</strong>：记录 Nacos 作为注册中心与配置中心的深度整合，以及 Feign 接口调优实践。</li><li><strong>流量防护</strong>：在高并发场景下，如何通过 Sentinel 或分布式限流保障系统不被瞬时流量冲垮。</li><li><strong>链路追踪</strong>：复杂微服务环境下的问题排查思路与监控方案。</li></ul><h3 id="_2-高并发与消息驱动-mq-cache" tabindex="-1">2. 高并发与消息驱动 (MQ &amp; Cache) <a class="header-anchor" href="#_2-高并发与消息驱动-mq-cache" aria-label="Permalink to “2. 高并发与消息驱动 (MQ &amp; Cache)”">​</a></h3><ul><li><strong>告警长城</strong>：基于百万级并发场景，利用 Redis 位图（Bitmap）或布隆过滤器优化查询性能的方案。</li><li><strong>异步解耦</strong>：Kafka 与 MQTT 的整合实战，特别是针对物联网（IoT）设备数据的实时接入与处理。</li><li><strong>缓存策略</strong>：解决缓存击穿、雪崩的实战代码片段，以及 Spring Cache 的深度自定义。</li></ul><h3 id="_3-数据持久化与复杂查询" tabindex="-1">3. 数据持久化与复杂查询 <a class="header-anchor" href="#_3-数据持久化与复杂查询" aria-label="Permalink to “3. 数据持久化与复杂查询”">​</a></h3><ul><li><strong>多库共存</strong>：MySQL 与 PostgreSQL 的选型思考及 Java 多数据源整合方案。</li><li><strong>检索增强</strong>：Elasticsearch 在海量日志检索与全文本搜索中的整合技巧。</li><li><strong>ORM 提效</strong>：MybatisPlus 的高级封装，如何减少重复代码，提升开发效率。</li></ul><hr><h2 id="🛠️-常规组件-怎么做-快速查阅" tabindex="-1">🛠️ 常规组件“怎么做”快速查阅 <a class="header-anchor" href="#🛠️-常规组件-怎么做-快速查阅" aria-label="Permalink to “🛠️ 常规组件“怎么做”快速查阅”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">目标场景</th><th style="text-align:left;">核心组件</th><th style="text-align:left;">关键点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>实时通信</strong></td><td style="text-align:left;">WebSocket / MQTT</td><td style="text-align:left;">长连接管理、断线重连、消息保序</td></tr><tr><td style="text-align:left;"><strong>任务调度</strong></td><td style="text-align:left;">Spring Task / XXL-Job</td><td style="text-align:left;">分布式环境下的任务不重复执行、动态执行</td></tr><tr><td style="text-align:left;"><strong>文件处理</strong></td><td style="text-align:left;">FTP / OSS / SFTP</td><td style="text-align:left;">大文件断点续传、并发上传性能调优</td></tr><tr><td style="text-align:left;"><strong>容器部署</strong></td><td style="text-align:left;">Docker / Compose</td><td style="text-align:left;">制作精简的 JRE 镜像、容器间网络互通配置</td></tr></tbody></table><hr><h2 id="💡-记录规则-每一个条目都包含" tabindex="-1">💡 记录规则：每一个条目都包含 <a class="header-anchor" href="#💡-记录规则-每一个条目都包含" aria-label="Permalink to “💡 记录规则：每一个条目都包含”">​</a></h2><ol><li><strong>场景复现</strong>：遇到了什么样的问题或需求？</li><li><strong>技术选型</strong>：为什么选择 A 组件而不是 B？</li><li><strong>整合步骤</strong>：核心依赖、配置类、核心业务逻辑代码。</li><li><strong>避坑指南</strong>：在整合过程中踩过的坑（比如 Docker 环境变量、Nginx 跨域等）。</li></ol><hr><h2 id="📂-点击左侧列表开始了解" tabindex="-1">📂 点击左侧列表开始了解 <a class="header-anchor" href="#📂-点击左侧列表开始了解" aria-label="Permalink to “📂 点击左侧列表开始了解”">​</a></h2>',18)])])}const x=e(n,[["render",i]]);export{f as __pageData,x as default};
